<script setup lang="ts">
import{CalendarDays,Cake,Edit3,Gift,Heart,LoaderCircle,MapPin,MoreHorizontal,Plus,Repeat2,Sparkles,Trash2,X}from'@lucide/vue';import{daysUntil,occurrence,type Anniversary,type AnniversaryKind}from'~/composables/useAnniversaries'
const{relationshipStart,loveDays,sorted,anniversariesLoading,loadAnniversaries,createAnniversary,updateAnniversary,deleteAnniversary}=useAnniversaries();const editorOpen=ref(false);const editing=ref<Anniversary|null>(null);const title=ref('');const eventDate=ref('');const kind=ref<AnniversaryKind>('anniversary');const recurring=ref(true);const note=ref('');const busy=ref(false);const error=ref('');const menuId=ref<string|null>(null)
const kinds={anniversary:{label:'纪念日',icon:Heart},birthday:{label:'生日',icon:Cake},travel:{label:'旅行',icon:MapPin},custom:{label:'特别日子',icon:Sparkles}}
onMounted(loadAnniversaries);function openCreate(){editing.value=null;title.value='';eventDate.value=new Date().toISOString().slice(0,10);kind.value='anniversary';recurring.value=true;note.value='';error.value='';editorOpen.value=true}function openEdit(x:Anniversary){editing.value=x;title.value=x.title;eventDate.value=x.eventDate;kind.value=x.kind;recurring.value=x.recurring;note.value=x.note;menuId.value=null;editorOpen.value=true}
async function save(){if(!title.value.trim()||!eventDate.value){error.value='请填写名称和日期';return}busy.value=true;try{const input={title:title.value.trim(),eventDate:eventDate.value,kind:kind.value,recurring:recurring.value,note:note.value.trim()};editing.value?await updateAnniversary(editing.value.id,input):await createAnniversary(input);editorOpen.value=false}catch(e:any){error.value=e.message}finally{busy.value=false}}async function remove(x:Anniversary){if(confirm('确定删除这个纪念日吗？')){try{await deleteAnniversary(x)}catch(e:any){alert(e.message)}}menuId.value=null}
function dateText(x:Anniversary){return new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'long',day:'numeric'}).format(occurrence(x))}function startText(){return new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'long',day:'numeric'}).format(new Date(`${relationshipStart.value}T12:00:00`))}
</script>
<template><section class="ann-view"><header class="ann-header"><div><p class="eyebrow">SPECIAL DAYS</p><h1>我们的纪念日</h1><span>记住重要的日子，也期待下一次共同庆祝。</span></div><button type="button" @click="openCreate"><Plus :size="18"/> 添加纪念日</button></header><section class="love-counter"><div><span><Heart :size="15" fill="currentColor"/> 我们在一起</span><LoveDuration :start="relationshipStart" layout="inline"/><p>从 {{startText()}} 开始，每分每秒都在继续</p></div><div class="counter-art"><Heart :size="54" fill="currentColor"/><i/><i/></div></section><div class="section-label"><span>即将到来</span><small>按距离今天的时间排列</small></div>
<div v-if="anniversariesLoading" class="ann-state"><LoaderCircle class="spin" :size="24"/> 正在计算特别日子</div><div v-else-if="!sorted.length" class="ann-state empty"><CalendarDays :size="38"/><h3>添加第一个特别日子</h3><p>生日、第一次旅行，或只有你们知道的日期。</p><button type="button" @click="openCreate">添加纪念日</button></div><div v-else class="ann-list"><article v-for="item in sorted" :key="item.id"><div class="date-badge"><span>{{String(occurrence(item).getMonth()+1).padStart(2,'0')}}</span><strong>{{String(occurrence(item).getDate()).padStart(2,'0')}}</strong></div><span class="kind-icon"><component :is="kinds[item.kind].icon" :size="20"/></span><div class="ann-copy"><div><h3>{{item.title}}</h3><span v-if="item.recurring"><Repeat2 :size="12"/> 每年</span></div><p v-if="item.note">{{item.note}}</p><footer>{{dateText(item)}} · {{kinds[item.kind].label}}</footer></div><div class="countdown"><strong>{{daysUntil(item)}}</strong><span>{{daysUntil(item)===0?'就是今天':'天后'}}</span></div><div class="ann-menu"><button type="button" aria-label="更多操作" @click="menuId=menuId===item.id?null:item.id"><MoreHorizontal :size="20"/></button><div v-if="menuId===item.id"><button type="button" @click="openEdit(item)"><Edit3 :size="15"/> 编辑</button><button class="danger" type="button" @click="remove(item)"><Trash2 :size="15"/> 删除</button></div></div></article></div>
<div v-if="editorOpen" class="editor-overlay" @click.self="editorOpen=false"><section class="ann-editor"><header><div><p class="eyebrow">SPECIAL DATE</p><h2>{{editing?'编辑纪念日':'添加纪念日'}}</h2></div><button type="button" aria-label="关闭" @click="editorOpen=false"><X :size="20"/></button></header><label><span>名称</span><input v-model="title" maxlength="80" placeholder="例如：第一次见面的日子"></label><div class="field-grid"><label><span>日期</span><input v-model="eventDate" type="date"></label><label><span>类型</span><select v-model="kind"><option value="anniversary">纪念日</option><option value="birthday">生日</option><option value="travel">旅行</option><option value="custom">特别日子</option></select></label></div><label><span>备注</span><textarea v-model="note" maxlength="300" rows="3" placeholder="关于这一天的故事"></textarea></label><label class="repeat-toggle"><input v-model="recurring" type="checkbox"><span><strong>每年重复</strong><small>自动计算下一次到来的日期</small></span></label><p v-if="error" class="editor-error">{{error}}</p><footer><button type="button" @click="editorOpen=false">取消</button><button class="save" type="button" :disabled="busy" @click="save"><LoaderCircle v-if="busy" class="spin" :size="17"/><Gift v-else :size="17"/> 保存纪念日</button></footer></section></div></section></template>
<style scoped>
