ng:4px 0 6px;color:#8a5e6d;font-size:19px}.kind-icon{display:grid;place-items:center;width:41px;height:41px;flex:0 0 41px;border-radius:14px;background:#eee9f8;color:#7b62a2}.ann-copy{min-width:0;flex:1}.ann-copy>div{display:flex;align-items:center;gap:8px}.ann-copy h3{margin:0;font-size:13px}.ann-copy>div>span{display:flex;align-items:center;gap:4px;padding:3px 6px;border-radius:7px;background:#f0ebf5;color:#8069a0;font-size:8px}.ann-copy p{margin:5px 0 0;color:#8d8492;font-size:10px}.ann-copy footer{margin-top:7px;color:#a198a7;font-size:9px}.countdown{text-align:right}.countdown strong,.countdown span{display:block}.countdown strong{font-size:23px}.countdown span{color:#9a919f;font-size:8px}.ann-menu{position:relative}.ann-menu>button{display:grid;place-items:center;width:34px;height:34px;border:0;border-radius:11px;background:transparent;color:#918897}.ann-menu>div{position:absolute;z-index:3;right:0;top:37px;width:105px;padding:5px;border:1px solid #e8e1eb;border-radius:11px;background:white;box-shadow:0 12px 28px rgba(60,47,72,.12)}.ann-menu>div button{display:flex;align-items:center;gap:7px;width:100%;padding:8px;border:0;border-radius:8px;background:transparent;font-size:10px}.ann-menu .danger{color:#bd5776}.ann-state{display:flex;align-items:center;justify-content:center;gap:8px;min-height:280px;color:#918999;font-size:11px}.ann-state.empty{flex-direction:column}.ann-state.empty svg{color:#b89fd8}.ann-state h3{margin:7px 0 0;color:#403a46}.ann-state p{margin:0}.ann-state button{margin-top:10px;padding:10px 14px;border:0;border-radius:12px;background:#eee9f8;color:#765ca6;font-weight:700}.editor-overlay{position:fixed;z-index:60;inset:0;display:grid;place-items:center;padding:20px;background:rgba(45,39,52,.28);backdrop-filter:blur(10px)}.ann-editor{width:min(100%,510px);padding:27px;border:1px solid rgba(255,255,255,.9);border-radius:24px;background:#fdfcfe}.ann-editor>header{display:flex;justify-content:space-between;margin-bottom:22px}.ann-editor h2{margin:0;font-size:23px}.ann-editor>header button{display:grid;place-items:center;width:37px;height:37px;border:0;border-radius:12px;background:#f0ebf5}.ann-editor>label,.field-grid label{display:block;margin-top:15px}.ann-editor label>span:not(.repeat-toggle span){display:block;margin-bottom:8px;color:#655e6c;font-size:11px;font-weight:700}.ann-editor input:not([type=checkbox]),.ann-editor textarea,.ann-editor select{width:100%;padding:13px;border:1px solid #e5dfe8;border-radius:13px;outline:0;background:white;font:inherit;font-size:12px}.ann-editor textarea{resize:vertical}.field-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.repeat-toggle{display:flex!important;align-items:center;gap:11px;padding:13px;border-radius:13px;background:#f5f1f8}.repeat-toggle input{width:17px;height:17px;accent-color:#8f72b9}.repeat-toggle strong,.repeat-toggle small{display:block}.repeat-toggle strong{font-size:11px}.repeat-toggle small{margin-top:3px;color:#958c9c;font-size:8px}.editor-error{color:#bd5776;font-size:10px}.ann-editor>footer{display:flex;justify-content:flex-end;gap:9px;margin-top:22px}.ann-editor>footer button{display:flex;align-items:center;gap:7px;min-height:42px;padding:0 16px;border:0;border-radius:13px;background:#f0ebf3;font-size:11px;font-weight:700}.ann-editor>footer .save{background:#332f3a;color:white}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}
